```cpp
#include <iostream>
#include <unistd.h>
#include <sys/types.h>
#include <sys/wait.h>
#include <fcntl.h>

int main() {
    int fd[2]; // Pipe file descriptors
    pid_t pid;

    // Create pipe
    if (pipe(fd) == -1) {
        std::cerr << "Pipe failed" << std::endl;
        return 1;
    }

    // Fork
    pid = fork();
    if (pid == -1) {
        std::cerr << "Fork failed" << std::endl;
        return 1;
    }

    if (pid == 0) { // Child process
        // Close unnecessary file descriptors in child
        close(fd[1]); // Close write end of the pipe

        // Redirect stdin and stdout to the pipe
        dup2(fd[0], STDIN_FILENO);
        dup2(fd[0], STDOUT_FILENO);

        // Close the pipe file descriptor
        close(fd[0]);

        // Execute a command, e.g., cat
        execlp("cat", "cat", (char *)0);
        std::cerr << "Exec failed" << std::endl;
        _exit(1);
    } else { // Parent process
        // Close unnecessary file descriptors in parent
        close(fd[0]); // Close read end of the pipe

        // Write to the pipe (optional, replace with your input)
        std::string input = "Hello from parent!";
        write(fd[1], input.c_str(), input.size());

        // Close the write end of the pipe
        close(fd[1]);

        // Wait for child to terminate
        wait(NULL);

        return 0;
    }
}
```

In this example:
- We create a pipe to share data between the parent and child processes.
- The child process redirects its `stdin` and `stdout` to the read end of the pipe.
- The parent process writes data to the write end of the pipe.

This setup allows the child process to read and write through the same file descriptor, effectively connecting its input and output to the pipe.
